      expect(screen.getByText("Muuda häälduskuju")).toBeInTheDocument();
    });

    it("renders close button", () => {
      render(<SentencePhoneticPanel {...defaultProps} />);
      expect(screen.getByLabelText("Sulge")).toBeInTheDocument();
