// SPDX-License-Identifier: MIT
// Copyright (c) 2024-2026 Askend Lab

import { describe, it, expect, vi, beforeEach } from "vitest";
import { createAudioPlayer, playAudioWithCallbacks } from "./audioPlayer";

interface MockAudioInstance {
  src: string;
  onloadeddata: (() => void) | null;
  onended: (() => void) | null;
  onerror: (() => void) | null;
  pause: ReturnType<typeof vi.fn>;
  play: ReturnType<typeof vi.fn>;
}

describe("audioPlayer", () => {
  let mockAudio: MockAudioInstance;

  beforeEach(() => {
    vi.clearAllMocks();

    class MockAudio {
      src = "";
      onloadeddata: (() => void) | null = null;
      onended: (() => void) | null = null;
      onerror: (() => void) | null = null;
      pause = vi.fn();
      play = vi.fn().mockResolvedValue(undefined);

      constructor(url?: string) {
        if (url) this.src = url;
        mockAudio = this;
      }
    }

    global.Audio = MockAudio as unknown as typeof Audio;
    global.URL.revokeObjectURL = vi.fn();
  });

  describe("createAudioPlayer", () => {
    it("should create audio player with callbacks", () => {
      const onLoaded = vi.fn();
      const onEnded = vi.fn();
      const onError = vi.fn();

      const { audio, cleanup } = createAudioPlayer(
        "https://example.com/audio.mp3",
        {
          onLoaded,
          onEnded,
          onError,
        },
      );

      expect(audio).toBe(mockAudio);
      expect(mockAudio.src).toBe("https://example.com/audio.mp3");

      mockAudio.onloadeddata!();
      expect(onLoaded).toHaveBeenCalled();

      mockAudio.onended!();
      expect(onEnded).toHaveBeenCalled();
      expect(global.URL.revokeObjectURL).toHaveBeenCalledWith(
        "https://example.com/audio.mp3",
      );

      cleanup();
    });

    it("should not revoke URL if shouldRevokeUrl is false", () => {
      const { cleanup } = createAudioPlayer(
        "https://example.com/audio.mp3",
        {},
        false,
      );

      mockAudio.onended!();
      expect(global.URL.revokeObjectURL).not.toHaveBeenCalled();

      cleanup();
    });

    it("should handle error callback", () => {
      const onError = vi.fn();

      createAudioPlayer("https://example.com/audio.mp3", { onError });

      mockAudio.onerror!();
      expect(onError).toHaveBeenCalled();
      expect(global.URL.revokeObjectURL).toHaveBeenCalled();
    });
  });

  describe("playAudioWithCallbacks", () => {
    it("should play audio and resolve on success", async () => {
      const onLoaded = vi.fn();
      const onEnded = vi.fn();

      const playPromise = playAudioWithCallbacks(
        "https://example.com/audio.mp3",
        {
          onLoaded,
          onEnded,
        },
      );

      mockAudio.onloadeddata!();
      expect(onLoaded).toHaveBeenCalled();

      mockAudio.onended!();
      await playPromise;

      expect(onEnded).toHaveBeenCalled();
      expect(mockAudio.play).toHaveBeenCalled();
    });

    it("should reject on error", async () => {
      const onError = vi.fn();

      const playPromise = playAudioWithCallbacks(
        "https://example.com/audio.mp3",
        { onError },
      );

      mockAudio.onerror!();

      await expect(playPromise).rejects.toThrow("Audio playback failed");
      expect(onError).toHaveBeenCalled();
    });

    it("should reject on play failure", async () => {
      class MockAudioWithError {
        src = "";
        onloadeddata: (() => void) | null = null;
        onended: (() => void) | null = null;
        onerror: (() => void) | null = null;
        pause = vi.fn();
        play = vi.fn().mockRejectedValue(new Error("Play failed"));

        constructor(url?: string) {
          if (url) this.src = url;
          mockAudio = this;
        }
      }

      global.Audio = MockAudioWithError as unknown as typeof Audio;

      await expect(
        playAudioWithCallbacks("https://example.com/audio.mp3"),
      ).rejects.toThrow();
    });

    it("should work without callbacks", async () => {
      const playPromise = playAudioWithCallbacks(
        "https://example.com/audio.mp3",
      );

      mockAudio.onended!();
      await playPromise;

      expect(mockAudio.play).toHaveBeenCalled();
    });

    it("should revoke URL on ended when shouldRevokeUrl is true", async () => {
      const playPromise = playAudioWithCallbacks(
        "blob:https://example.com/audio",
        {},
        true,
      );

      mockAudio.onended!();
      await playPromise;

      expect(global.URL.revokeObjectURL).toHaveBeenCalledWith(
        "blob:https://example.com/audio",
      );
    });

    it("should not revoke URL when shouldRevokeUrl is false", async () => {
      const playPromise = playAudioWithCallbacks(
        "https://example.com/audio.mp3",
        {},
        false,
      );

      mockAudio.onended!();
      await playPromise;

      expect(global.URL.revokeObjectURL).not.toHaveBeenCalled();
    });

    it("should revoke URL on error", async () => {
      const playPromise = playAudioWithCallbacks(
        "blob:https://example.com/audio",
        {},
        true,
      );

      mockAudio.onerror!();

      await expect(playPromise).rejects.toThrow("Audio playback failed");
      expect(global.URL.revokeObjectURL).toHaveBeenCalledWith(
        "blob:https://example.com/audio",
      );
    });
  });
});

src/utils/phoneticMarkers.full.test.ts.source:
// SPDX-License-Identifier: MIT
// Copyright (c) 2024-2026 Askend Lab

import { describe, it, expect } from "vitest";
import {
  stripPhoneticMarkers,
  transformToUI,
  transformToVabamorf,
} from "./phoneticMarkers";

describe("phoneticMarkers full coverage", () => {
  describe("stripPhoneticMarkers", () => {
    it("strips grave accent", () => {
      expect(stripPhoneticMarkers("te`st")).toBe("test");
    });
    it("strips acute accent", () => {
      expect(stripPhoneticMarkers("te´st")).toBe("test");
    });
    it("strips apostrophe", () => {
      expect(stripPhoneticMarkers("te'st")).toBe("test");
    });
    it("strips plus sign", () => {
      expect(stripPhoneticMarkers("te+st")).toBe("test");
    });
    it("handles multiple markers", () => {
      expect(stripPhoneticMarkers("te`s´t+a")).toBe("testa");
    });
    it("handles empty string", () => {
      expect(stripPhoneticMarkers("")).toBe("");
    });
    it("handles no markers", () => {
      expect(stripPhoneticMarkers("hello")).toBe("hello");
    });
  });

  describe("transformToUI", () => {
    it("transforms < to grave", () => {
      expect(transformToUI("te<st")).toBe("te`st");
    });
    it("transforms ? to acute", () => {
      expect(transformToUI("te?st")).toBe("te´st");
    });
    it("transforms _ to plus", () => {
      expect(transformToUI("te_st")).toBe("te+st");
    });
    it("handles null", () => {
      expect(transformToUI(null)).toBeNull();
    });
    it("handles empty string", () => {
      expect(transformToUI("")).toBe("");
    });
    it("handles multiple transformations", () => {
      expect(transformToUI("a<b?c_d")).toBe("a`b´c+d");
    });
  });

  describe("transformToVabamorf", () => {
    it("transforms grave to <", () => {
      expect(transformToVabamorf("te`st")).toBe("te<st");
    });
    it("transforms acute to ?", () => {
      expect(transformToVabamorf("te´st")).toBe("te?st");
    });
    it("transforms plus to _", () => {
      expect(transformToVabamorf("te+st")).toBe("te_st");
    });
    it("handles null", () => {
      expect(transformToVabamorf(null)).toBeNull();
    });
    it("handles empty string", () => {
      expect(transformToVabamorf("")).toBe("");
    });
    it("handles multiple transformations", () => {
      expect(transformToVabamorf("a`b´c+d")).toBe("a<b?c_d");
    });
  });
});
